package sn.gestionimmobiliere.backend.billing.domain;
import java.time.*;import java.util.UUID;import jakarta.persistence.*;
@Entity @Table(name="payments") public class Payment{@Id private UUID id;@Column(name="organization_id")private UUID organizationId;@Column(name="rent_charge_id")private UUID rentChargeId;private long amount;@Column(name="payment_date")private LocalDate paymentDate;@Enumerated(EnumType.STRING)private PaymentMethod method;private String reference;private String status="CONFIRMED";@Column(name="created_at")private Instant createdAt;protected Payment(){}public Payment(UUID id,UUID org,UUID chargeId,long amount,LocalDate date,PaymentMethod method,String reference,Instant now){this.id=id;organizationId=org;rentChargeId=chargeId;this.amount=amount;paymentDate=date;this.method=method;this.reference=reference;createdAt=now;}public UUID getId(){return id;}public UUID getRentChargeId(){return rentChargeId;}public long getAmount(){return amount;}public LocalDate getPaymentDate(){return paymentDate;}public PaymentMethod getMethod(){return method;}public String getReference(){return reference;}public String getStatus(){return status;}public Instant getCreatedAt(){return createdAt;}}
